script:
const content = document.getElementById('win-content-' + winObj.id);
content.innerHTML = '<div class="p-4 flex flex-col h-full bg-slate-900 text-white select-none"><div class="flex justify-between items-center bg-black/40 border border-slate-800 rounded-lg p-3 mb-3 shrink-0"><div class="text-center"><div class="text-[10px] uppercase tracking-wider text-slate-400">Moves</div><div class="puzzle-moves text-xl font-bold font-mono text-cyan-400">0</div></div><div class="text-center"><div class="text-[10px] uppercase tracking-wider text-slate-400">Time</div><div class="puzzle-time text-xl font-bold font-mono text-amber-400">00:00</div></div></div><div class="flex-1 flex items-center justify-center bg-black/20 rounded-xl border border-slate-800 relative p-3 mb-3"><div class="puzzle-grid grid grid-cols-4 gap-2 w-full max-w-[320px] aspect-square bg-slate-950 p-2 rounded-lg border border-slate-800 relative"></div><div class="puzzle-overlay absolute inset-0 flex flex-col items-center justify-center bg-black/80 p-6 text-center space-y-4 rounded-xl"><h3 class="text-lg font-bold text-sky-400">🧩 经典数字华容道</h3><p class="text-xs text-slate-400 max-w-[260px]">将打乱的数字按 1 至 15 的顺序重新排列。支持 iPad 全屏触控滑行！</p><button class="btn-start px-5 py-2 bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-400 hover:to-blue-500 text-xs font-bold rounded-lg border border-cyan-400/30 text-white shadow-lg shadow-cyan-500/20">开始挑战</button></div></div><div class="flex justify-between text-[11px] opacity-60 px-1 shrink-0"><span class="puzzle-best-moves">最佳步数: --</span></div></div>';

const gridContainer = content.querySelector('.puzzle-grid');
const movesText = content.querySelector('.puzzle-moves');
const timeText = content.querySelector('.puzzle-time');
const overlay = content.querySelector('.puzzle-overlay');
const bestMovesText = content.querySelector('.puzzle-best-moves');
const btnStart = content.querySelector('.btn-start');

let board = [];
let moves = 0;
let startTime = null;
let timerInterval = null;
let isPlaying = false;
const size = 4;

const triggerSound = (freq, type, duration) => {
  if (typeof playSystemSound === 'function') {
    playSystemSound(freq, type, duration);
  } else {
    try {
      const AudioCtx = window.AudioContext || window.webkitAudioContext;
      if (!AudioCtx) return;
      const audioCtx = new AudioCtx();
      const osc = audioCtx.createOscillator();
      const gain = audioCtx.createGain();
      osc.type = type || 'sine';
      osc.frequency.setValueAtTime(freq, audioCtx.currentTime);
      gain.gain.setValueAtTime(0.06, audioCtx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.001, audioCtx.currentTime + duration);
      osc.connect(gain);
      gain.connect(audioCtx.destination);
      osc.start();
      osc.stop(audioCtx.currentTime + duration);
    } catch(e) {}
  }
};

window.jros_puzzle_records = window.jros_puzzle_records || {};
const appRecordKey = winObj.id || 'default';
window.jros_puzzle_records[appRecordKey] = window.jros_puzzle_records[appRecordKey] || { bestMoves: Infinity };

const updateBestDisplay = () => {
  const best = window.jros_puzzle_records[appRecordKey].bestMoves;
  bestMovesText.innerText = '最佳步数: ' + (best === Infinity ? '--' : best + ' 步');
};
updateBestDisplay();

const isSolvable = (arr) => {
  let invCount = 0;
  const len = arr.length;
  let blankRow = 0;
  for (let i = 0; i < len; i++) {
    if (arr[i] === 0) {
      blankRow = Math.floor(i / size);
      continue;
    }
    for (let j = i + 1; j < len; j++) {
      if (arr[j] !== 0 && arr[i] > arr[j]) invCount++;
    }
  }
  return (size % 2 === 1) ? (invCount % 2 === 0) : ((invCount + size - blankRow - 1) % 2 === 0);
};

const generateSolvableBoard = () => {
  let arr;
  do {
    arr = Array.from({ length: size * size }, (_, i) => (i + 1) % (size * size));
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
  } while (!isSolvable(arr) || isWin(arr));
  return arr;
};

const renderBoard = () => {
  gridContainer.innerHTML = '';
  board.forEach((val, index) => {
    const cell = document.createElement('div');
    cell.dataset.index = index;
    if (val === 0) {
      cell.className = 'bg-slate-950 rounded-md border border-dashed border-slate-800/50';
    } else {
      cell.className = 'bg-gradient-to-b from-slate-800 to-slate-850 border border-slate-700/80 rounded-md flex items-center justify-center font-mono font-bold text-lg text-cyan-400 cursor-pointer shadow-md active:scale-95 transition-all duration-100 select-none shadow-black/40';
      cell.innerText = val;
    }
    gridContainer.appendChild(cell);
  });
};

const isWin = (currBoard) => {
  for (let i = 0; i < currBoard.length - 1; i++) {
    if (currBoard[i] !== i + 1) return false;
  }
  return currBoard[currBoard.length - 1] === 0;
};

const startTimer = () => {
  startTime = Date.now();
  clearInterval(timerInterval);
  timerInterval = setInterval(() => {
    const elapsed = Math.floor((Date.now() - startTime) / 1000);
    const m = String(Math.floor(elapsed / 60)).padStart(2, '0');
    const s = String(elapsed % 60).padStart(2, '0');
    timeText.innerText = m + ':' + s;
  }, 1000);
};

const handleCellClick = (e) => {
  if (!isPlaying) return;
  const cell = e.target.closest('[data-index]');
  if (!cell) return;
  const idx = parseInt(cell.dataset.index);
  if (board[idx] === 0) return;

  const row = Math.floor(idx / size);
  const col = idx % size;
  const blankIdx = board.indexOf(0);
  const blankRow = Math.floor(blankIdx / size);
  const blankCol = blankIdx % size;

  const isNeighbor = (Math.abs(row - blankRow) + Math.abs(col - blankCol)) === 1;
  if (isNeighbor) {
    [board[idx], board[blankIdx]] = [board[blankIdx], board[idx]];
    moves++;
    movesText.innerText = moves;
    renderBoard();
    triggerSound(450 + (board[blankIdx] * 15), 'sine', 0.05);

    if (isWin(board)) {
      endGame(true);
    }
  } else {
    triggerSound(180, 'sawtooth', 0.08);
  }
  e.preventDefault();
};

const endGame = (hasWon) => {
  isPlaying = false;
  clearInterval(timerInterval);
  if (hasWon) {
    triggerSound(523.25, 'triangle', 0.15);
    setTimeout(() => triggerSound(659.25, 'triangle', 0.15), 120);
    setTimeout(() => triggerSound(783.99, 'triangle', 0.25), 240);
    if (moves < window.jros_puzzle_records[appRecordKey].bestMoves) {
      window.jros_puzzle_records[appRecordKey].bestMoves = moves;
    }
    updateBestDisplay();
    overlay.innerHTML = '<h3 class="text-xl font-bold text-emerald-400">🎉 完美通关！</h3><p class="text-xs text-slate-400">耗时: ' + timeText.innerText + ' | 总步数: ' + moves + ' 步</p><button class="btn-start px-5 py-2 bg-gradient-to-r from-emerald-500 to-teal-600 hover:from-emerald-400 hover:to-teal-500 text-xs font-bold rounded-lg border border-emerald-400/30 text-white shadow-lg">再来一局</button>';
  } else {
    overlay.innerHTML = '<h3 class="text-lg font-bold text-sky-400">经典数字华容道</h3><p class="text-xs text-slate-400 max-w-[260px]">将打乱的数字按 1 至 15 的顺序重新排列。</p><button class="btn-start px-5 py-2 bg-gradient-to-r from-cyan-500 to-blue-600 hover:from-cyan-400 hover:to-blue-500 text-xs font-bold rounded-lg text-white shadow-lg">重新挑战</button>';
  }
  overlay.querySelector('.btn-start').onclick = initGame;
  overlay.classList.remove('hidden');
};

const initGame = () => {
  overlay.classList.add('hidden');
  board = generateSolvableBoard();
  moves = 0;
  movesText.innerText = '0';
  timeText.innerText = '00:00';
  renderBoard();
  startTimer();
  isPlaying = true;
  triggerSound(587.33, 'triangle', 0.1);
  setTimeout(() => triggerSound(880, 'triangle', 0.15), 80);
};

btnStart.onclick = initGame;
gridContainer.addEventListener('pointerdown', handleCellClick);

winObj.onDestroy = () => {
  clearInterval(timerInterval);
  gridContainer.removeEventListener('pointerdown', handleCellClick);
};
